mapper.select:
select distinct q.id, q.title, q.difficulty from question q left join question_tag qt on qt.question_id = q.id left join tag t on t.id = qt.tag_id where q.is_public = 1 and q.parent_id = 0 and q.is_deleted = 0
and (q.title like concat('%', #{content}, '%') or q.content like concat('%', #{content}, '%') or t.name like concat('%', #{content}, '%'))
and t.id = #{tagId}
